    {"id": "inno_trans_222", "name_en": "Carbon Lock-in", "name_ja": "炭素ロックイン", "definition": "化石燃料依存の社会技術システムが技術的・制度的・行動的に固定化されている状態を分析するフレームワーク。技術システム・政策的支援・社会的慣行の相互強化によるロックインメカニズムを理論化する。", "impact_summary": "脱炭素化の構造的障壁を体系的に特定し、気候政策の設計に根本的な示唆を提供", "school_of_thought": "MLP学派", "era_start": 2000, "innovation_type": "systemic,sustainability", "cognitive_mechanism": "lock-in,systemic", "key_researchers": ["Gregory Unruh"], "key_works": ["Understanding carbon lock-in (2000)", "Escaping carbon lock-in (2002)"], "keywords_ja": "炭素ロックイン,化石燃料,脱炭素,経路依存", "keywords_en": "carbon lock-in, fossil fuels, decarbonization, path dependence", "opposing_concept_names": "carbon unlock, path creation", "schumpeter_layer": "macro"},
    {"id": "inno_trans_223", "name_en": "Phase Model of Transitions", "name_ja": "トランジションの段階モデル", "definition": "社会技術トランジションの時間的展開を4段階—前発展期・離陸期・加速期・安定化期—に区分するモデル。各段階の特徴的パターンとガバナンス課題を分析する。", "impact_summary": "トランジションの時間的進行を体系化し、段階に応じた政策介入の設計を支援", "school_of_thought": "MLP学派", "era_start": 2001, "innovation_type": "systemic", "cognitive_mechanism": "processual,temporal", "key_researchers": ["Jan Rotmans", "René Kemp", "Martijn van Asselt"], "key_works": ["More evolution than revolution: Transition management in public policy (2001)"], "keywords_ja": "段階モデル,前発展,離陸,加速,安定化", "keywords_en": "phase model, pre-development, take-off, acceleration, stabilisation", "opposing_concept_names": "non-linear transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_224", "name_en": "Transition Management", "name_ja": "トランジション・マネジメント", "definition": "持続可能性トランジションを意図的に方向づけ促進するガバナンスアプローチ。長期ビジョン設定・実験的学習・適応的管理を組み合わせた4段階の政策サイクルを提案する。", "impact_summary": "オランダを中心にトランジション政策の実践的フレームワークとして広く採用され、欧州の環境・エネルギー政策に大きな影響", "school_of_thought": "トランジション論", "era_start": 2001, "innovation_type": "systemic,governance", "cognitive_mechanism": "governance,adaptive", "key_researchers": ["Jan Rotmans", "René Kemp", "Derk Loorbach"], "key_works": ["Transition Management: New mode of governance for sustainable development (2007)"], "keywords_ja": "トランジションマネジメント,ガバナンス,ビジョン,実験,適応的管理", "keywords_en": "transition management, governance, visioning, experimentation, adaptive management", "opposing_concept_names": "top-down regulation, market-based policy", "schumpeter_layer": "macro"},
    {"id": "inno_trans_225", "name_en": "Transition Arena", "name_ja": "トランジション・アリーナ", "definition": "トランジションマネジメントの中核的手法。多様なステークホルダーが参加する討議の場を設定し、共有ビジョンの構築・実験計画の策定・社会学習の促進を行う参加型ガバナンスプロセス。", "impact_summary": "トランジションマネジメントの実践的ツールとして多くの自治体で採用され、参加型ガバナンスの革新に貢献", "school_of_thought": "トランジション論", "era_start": 2007, "innovation_type": "governance,participatory", "cognitive_mechanism": "deliberation,co-creation", "key_researchers": ["Derk Loorbach"], "key_works": ["Transition Management: New mode of governance for sustainable development (2007)"], "keywords_ja": "トランジションアリーナ,参加型,ステークホルダー,ビジョン構築,社会学習", "keywords_en": "transition arena, participatory, stakeholder, visioning, social learning", "opposing_concept_names": "expert-driven policy", "schumpeter_layer": "meso"},
    {"id": "inno_trans_226", "name_en": "Transition Experiments", "name_ja": "トランジション実験", "definition": "持続可能性トランジションを促進するための社会的実験の概念と方法論。保護された空間での革新的実践の試行を通じて、システム変革のための学習と知識蓄積を行う。", "impact_summary": "政策実験としてのリビングラボ・パイロットプロジェクトの理論的基盤を提供し、実験的ガバナンスを正当化", "school_of_thought": "トランジション論", "era_start": 2006, "innovation_type": "systemic,experimental", "cognitive_mechanism": "experimentation,learning", "key_researchers": ["Flor Avelino", "Julia Wittmayer"], "key_works": ["Transition experiments: A framework for understanding sustainability-oriented experiments (2006)"], "keywords_ja": "トランジション実験,社会実験,リビングラボ,学習,保護空間", "keywords_en": "transition experiments, social experiments, living labs, learning, protected space", "opposing_concept_names": "blueprint planning", "schumpeter_layer": "meso"},
    {"id": "inno_trans_227", "name_en": "Reflexive Governance for Sustainability", "name_ja": "持続可能性のための再帰的ガバナンス", "definition": "複雑で不確実な持続可能性課題に対応するための再帰的ガバナンスの理論。政策システム自体の前提・目標・手段を継続的に問い直し、システム的学習を通じて適応する統治アプローチ。", "impact_summary": "従来の線形的政策モデルを超え、不確実性下での適応的ガバナンスの理論的基盤を提供", "school_of_thought": "トランジション論", "era_start": 2006, "innovation_type": "governance,reflexive", "cognitive_mechanism": "reflexivity,meta-governance", "key_researchers": ["Jan-Peter Voß", "Dierk Bauknecht", "René Kemp"], "key_works": ["Reflexive Governance for Sustainable Development (2006)"], "keywords_ja": "再帰的ガバナンス,適応的管理,不確実性,システム学習,持続可能性", "keywords_en": "reflexive governance, adaptive management, uncertainty, systemic learning, sustainability", "opposing_concept_names": "rational-comprehensive planning", "schumpeter_layer": "macro"},
    {"id": "inno_trans_228", "name_en": "Strategic Niche Management (SNM) Extensions", "name_ja": "戦略的ニッチマネジメント（SNM）拡張", "definition": "ケンプらが開発した戦略的ニッチマネジメントの拡張。SNMの3つの内部プロセス—ビジョン形成・ネットワーク構築・学習—を精緻化し、ニッチ管理の成功要因と失敗要因を体系化する。", "impact_summary": "ニッチ育成政策の設計に具体的なガイダンスを提供し、技術実証プロジェクトの評価枠組みとして活用", "school_of_thought": "MLP学派", "era_start": 1998, "innovation_type": "systemic,strategic", "cognitive_mechanism": "management,learning", "key_researchers": ["René Kemp", "Johan Schot", "Arie Rip"], "key_works": ["Regime shifts to sustainability through processes of niche formation (1998)"], "keywords_ja": "SNM,戦略的ニッチマネジメント,ビジョン,ネットワーク,学習", "keywords_en": "SNM, strategic niche management, visioning, networking, learning", "opposing_concept_names": "market-led diffusion", "schumpeter_layer": "meso"},
    {"id": "inno_trans_229", "name_en": "Niche Accumulation Dynamics", "name_ja": "ニッチ蓄積ダイナミクス", "definition": "複数のニッチ実験の経験と学習が蓄積され、グローバルニッチとしての制度的成熟に至るプロセスの理論。ローカルな実験の知識がいかにしてグローバルな制度変化に寄与するかを分析する。", "impact_summary": "個別ニッチ実験を超えた累積的学習プロセスの重要性を理論化", "school_of_thought": "MLP学派", "era_start": 2008, "innovation_type": "systemic", "cognitive_mechanism": "accumulation,scaling", "key_researchers": ["Frank Geels", "Rob Raven"], "key_works": ["Non-linearity and expectations in niche-development trajectories (2006)"], "keywords_ja": "ニッチ蓄積,累積学習,グローバルニッチ,スケーリング", "keywords_en": "niche accumulation, cumulative learning, global niche, scaling", "opposing_concept_names": "single niche focus", "schumpeter_layer": "meso"},
    {"id": "inno_trans_230", "name_en": "MLP and Digital Technologies", "name_ja": "MLPとデジタル技術", "definition": "デジタル技術（AI・IoT・プラットフォーム）がMLPの3層構造に与える変革的影響を分析する拡張。デジタルプラットフォームによるニッチの急速拡大やレジーム破壊のメカニズムを理論化する。", "impact_summary": "デジタルトランスフォーメーションとサステナビリティトランジションの交差領域の分析枠組みを提供", "school_of_thought": "MLP学派", "era_start": 2019, "innovation_type": "systemic,digital", "cognitive_mechanism": "digital,platform", "key_researchers": ["Jochen Markard"], "key_works": ["The next phase of the energy transition and its implications for research and policy (2018)"], "keywords_ja": "MLP,デジタル,プラットフォーム,AI,IoT,破壊的革新", "keywords_en": "MLP, digital, platform, AI, IoT, disruptive innovation", "opposing_concept_names": "analog transition theory", "schumpeter_layer": "macro"},
    {"id": "inno_trans_231", "name_en": "MLP and Decline Studies", "name_ja": "MLPと衰退研究", "definition": "MLPを技術革新の出現だけでなく、既存技術・産業の衰退プロセスの分析に応用する拡張。化石燃料産業の計画的衰退（フェーズアウト）のガバナンスを分析する。", "impact_summary": "「創造的破壊」の「破壊」側面を正面から分析し、公正なフェーズアウト政策の理論的基盤を提供", "school_of_thought": "MLP学派", "era_start": 2019, "innovation_type": "systemic,sustainability", "cognitive_mechanism": "decline,phase-out", "key_researchers": ["Andy Turnheim", "Frank Geels"], "key_works": ["The destabilisation of existing regimes: Confronting a multi-dimensional framework (2012)"], "keywords_ja": "MLP,衰退,フェーズアウト,化石燃料,既存産業", "keywords_en": "MLP, decline, phase-out, fossil fuels, incumbent industries", "opposing_concept_names": "innovation-only transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_232", "name_en": "Whole System Reconfiguration", "name_ja": "システム全体の再構成", "definition": "個別セクターのトランジションを超え、エネルギー・輸送・食料・住居等の複数システムが同時に再構成されるプロセスの理論。システム間の相互依存性と波及効果を分析する。", "impact_summary": "セクター別政策の限界を指摘し、統合的システム変革アプローチの必要性を理論化", "school_of_thought": "MLP学派", "era_start": 2019, "innovation_type": "systemic,sustainability", "cognitive_mechanism": "holistic,systemic", "key_researchers": ["Frank Geels", "Benjamin Sovacool"], "key_works": ["Sociotechnical transitions for deep decarbonization (2017)"], "keywords_ja": "システム再構成,統合的変革,セクター横断,相互依存", "keywords_en": "whole system reconfiguration, integrated transformation, cross-sectoral, interdependence", "opposing_concept_names": "sectoral transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_233", "name_en": "MLP and Backlash Dynamics", "name_ja": "MLPとバックラッシュダイナミクス", "definition": "持続可能性トランジションに対する政治的・社会的反発のメカニズムをMLPフレームワークで分析する理論。レジーム行為者の抵抗戦略、ポピュリズム、「公正なトランジション」への不満を扱う。", "impact_summary": "トランジションの社会的受容性の問題を正面から分析し、包摂的トランジション政策の必要性を理論化", "school_of_thought": "MLP学派", "era_start": 2020, "innovation_type": "systemic,social,political", "cognitive_mechanism": "resistance,backlash", "key_researchers": ["Frank Geels"], "key_works": ["Micro-foundations of the multi-level perspective on socio-technical transitions (2020)"], "keywords_ja": "MLP,バックラッシュ,抵抗,反発,社会的受容性", "keywords_en": "MLP, backlash, resistance, pushback, social acceptance", "opposing_concept_names": "smooth transition narrative", "schumpeter_layer": "macro"},
    {"id": "inno_trans_234", "name_en": "MLP Micro-foundations", "name_ja": "MLPのミクロ的基礎", "definition": "MLPの3層構造をミクロレベルの行為者の認知・戦略・相互作用から基礎づける理論的試み。構造的説明と行為者中心の説明を統合する社会学的基盤を構築する。", "impact_summary": "MLPの理論的厳密性を強化し、マクロ構造とミクロ行為の接続を明示化", "school_of_thought": "MLP学派", "era_start": 2020, "innovation_type": "systemic", "cognitive_mechanism": "micro-foundations,cognition", "key_researchers": ["Frank Geels"], "key_works": ["Micro-foundations of the multi-level perspective on socio-technical transitions (2020)"], "keywords_ja": "MLPミクロ的基礎,認知,戦略,行為者,構造と行為", "keywords_en": "MLP micro-foundations, cognition, strategy, actors, structure-agency", "opposing_concept_names": "macro-structural MLP", "schumpeter_layer": "micro"},
    {"id": "inno_trans_235", "name_en": "Expectations Dynamics in Transitions", "name_ja": "トランジションにおける期待のダイナミクス", "definition": "技術的・社会的革新に対する将来期待がトランジションプロセスに与える影響を分析する理論。期待の形成・共有・修正のプロセスがニッチの動員力と正当性に与える影響を理論化する。", "impact_summary": "「期待のソシオロジー」をトランジション研究に導入し、期待管理の政策的重要性を理論化", "school_of_thought": "MLP学派", "era_start": 2006, "innovation_type": "systemic", "cognitive_mechanism": "expectations,legitimation", "key_researchers": ["Kornelia Konrad", "Harro van Lente", "Cynthia Selin"], "key_works": ["The sociology of expectations in science and technology (2006)"], "keywords_ja": "期待,ハイプ,正当性,動員,将来ビジョン", "keywords_en": "expectations, hype, legitimacy, mobilisation, future visions", "opposing_concept_names": "rational technology assessment", "schumpeter_layer": "meso"},
    {"id": "inno_trans_236", "name_en": "Transition Geographies of Uneven Development", "name_ja": "不均等発展のトランジション地理学", "definition": "持続可能性トランジションの空間的不均等性—先進地域と後発地域、都市と農村、グローバルノースとサウスの格差—を分析するフレームワーク。トランジションの地理的公正性を問う。", "impact_summary": "トランジション研究にグローバルな空間的公正の視点を導入し、不均等発展の問題を可視化", "school_of_thought": "MLP学派", "era_start": 2015, "innovation_type": "systemic,spatial", "cognitive_mechanism": "spatial-justice,uneven", "key_researchers": ["Lars Coenen", "Bernhard Truffer", "Rob Raven"], "key_works": ["Local niche experimentation in energy transitions: A theoretical and empirical exploration (2015)"], "keywords_ja": "トランジション地理学,不均等発展,空間的公正,都市農村格差", "keywords_en": "transition geographies, uneven development, spatial justice, urban-rural gap", "opposing_concept_names": "spatially neutral transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_237", "name_en": "MLP and Emotional Dimensions", "name_ja": "MLPと感情的次元", "definition": "トランジションプロセスにおける感情—不安・希望・怒り・喪失感—の役割を分析する拡張。技術変化に伴うアイデンティティの変容と感情的反応がトランジションの速度と方向に与える影響を理論化する。", "impact_summary": "合理主義的なトランジション分析に感情的次元を追加し、社会的受容性の深層的理解を促進", "school_of_thought": "MLP学派", "era_start": 2019, "innovation_type": "systemic,social", "cognitive_mechanism": "emotional,identity", "key_researchers": ["Bruno Turnheim", "Frank Geels"], "key_works": ["Destabilisation of the existing regime: Emotions and loss in transition processes (2019)"], "keywords_ja": "MLP,感情,アイデンティティ,喪失,不安,希望", "keywords_en": "MLP, emotions, identity, loss, anxiety, hope", "opposing_concept_names": "rationalist MLP", "schumpeter_layer": "micro"},
    {"id": "inno_trans_238", "name_en": "Urban Transitions Framework", "name_ja": "都市トランジションフレームワーク", "definition": "都市を持続可能性トランジションの主要な単位として分析するフレームワーク。都市固有のインフラ・ガバナンス・市民社会の特性を考慮し、MLPを都市コンテクストに適応させる。", "impact_summary": "都市レベルのトランジション政策の理論的基盤を提供し、スマートシティ・グリーンシティ政策に影響", "school_of_thought": "MLP学派", "era_start": 2011, "innovation_type": "systemic,urban", "cognitive_mechanism": "urban,governance", "key_researchers": ["Harriet Bulkeley", "Vanesa Castán Broto", "Mike Hodson"], "key_works": ["Cities and low carbon transitions (2011)"], "keywords_ja": "都市トランジション,スマートシティ,都市ガバナンス,インフラ", "keywords_en": "urban transitions, smart city, urban governance, infrastructure", "opposing_concept_names": "national-level transition", "schumpeter_layer": "meso"},
    {"id": "inno_trans_239", "name_en": "Multi-Level Governance of Transitions", "name_ja": "トランジションの多層ガバナンス", "definition": "持続可能性トランジションのガバナンスが国際・国家・地域・都市の複数レベルで同時に展開されるプロセスの分析。レベル間の調整・衝突・補完の機能を理論化する。", "impact_summary": "単一レベルの政策分析を超え、多層的ガバナンスの調整課題を可視化", "school_of_thought": "トランジション論", "era_start": 2012, "innovation_type": "governance,systemic", "cognitive_mechanism": "multi-level,coordination", "key_researchers": ["James Meadowcroft", "Harriet Bulkeley"], "key_works": ["What about the politics? Sustainable development, transition management, and long term energy transitions (2011)"], "keywords_ja": "多層ガバナンス,調整,政策統合,レベル間関係", "keywords_en": "multi-level governance, coordination, policy integration, inter-level relations", "opposing_concept_names": "single-level governance", "schumpeter_layer": "macro"},
    {"id": "inno_trans_240", "name_en": "Transformative Innovation Policy", "name_ja": "変革的イノベーション政策", "definition": "従来のR&D支援・市場失敗是正型イノベーション政策を超え、システム変革を目指す第3世代のイノベーション政策フレームワーク。方向性設定・ニッチ育成・レジーム不安定化・需要側政策を統合する。", "impact_summary": "OECDや欧州委員会のイノベーション政策に大きな影響を与え、ミッション指向型政策の理論的基盤を提供", "school_of_thought": "トランジション論", "era_start": 2018, "innovation_type": "policy,systemic", "cognitive_mechanism": "directionality,systemic", "key_researchers": ["Johan Schot", "W. Edward Steinmueller"], "key_works": ["Three frames for innovation policy: R&D, systems of innovation and transformative change (2018)"], "keywords_ja": "変革的イノベーション政策,第3世代,ミッション指向,方向性,システム変革", "keywords_en": "transformative innovation policy, third frame, mission-oriented, directionality, system change", "opposing_concept_names": "market failure innovation policy, systems of innovation policy", "schumpeter_layer": "macro"},
    {"id": "inno_trans_241", "name_en": "Exnovation", "name_ja": "エクスノベーション", "definition": "持続不可能な技術・実践・制度を意図的に廃止・除去するプロセスの概念。イノベーション（新規導入）の対概念として、既存システムの計画的退出がトランジションに果たす役割を分析する。", "impact_summary": "「新しいものを入れる」だけでなく「古いものを出す」プロセスの政策的重要性を理論化", "school_of_thought": "トランジション論", "era_start": 2014, "innovation_type": "systemic,sustainability", "cognitive_mechanism": "removal,phase-out", "key_researchers": ["Mads Borup", "David Tyfield"], "key_works": ["The concept of exnovation: Contributions to a new paradigm for sustainability transitions (2017)"], "keywords_ja": "エクスノベーション,廃止,フェーズアウト,退出,持続不可能", "keywords_en": "exnovation, phase-out, removal, exit, unsustainable", "opposing_concept_names": "innovation-only approach", "schumpeter_layer": "macro"},
    {"id": "inno_trans_242", "name_en": "Windows of Opportunity in Transitions", "name_ja": "トランジションにおける機会の窓", "definition": "政策科学のキングドンモデルをトランジション研究に応用し、ランドスケープ圧力・レジームの不安定化・ニッチの成熟が同時に起こる「機会の窓」がトランジションの進展に不可欠であるとする理論。", "impact_summary": "トランジションの政治的タイミングの重要性を理論化し、戦略的介入の時期を特定する分析枠組みを提供", "school_of_thought": "MLP学派", "era_start": 2010, "innovation_type": "systemic,political", "cognitive_mechanism": "timing,opportunity", "key_researchers": ["Frank Geels", "Peter Stegmaier"], "key_works": ["The dynamics of sustainability transitions (2012)"], "keywords_ja": "機会の窓,タイミング,政治的機会,ランドスケープ圧力", "keywords_en": "windows of opportunity, timing, political opportunity, landscape pressure", "opposing_concept_names": "deterministic transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_243", "name_en": "Transition Governance Instruments Typology", "name_ja": "トランジションガバナンス手段の類型論", "definition": "持続可能性トランジションを促進するための政策手段を4つの機能—ニッチ育成・レジーム不安定化・制度変革・需要喚起—に分類する類型論。各機能に適した具体的政策ツールを体系化する。", "impact_summary": "トランジション政策のツールキットを体系化し、包括的な政策パッケージの設計を支援", "school_of_thought": "トランジション論", "era_start": 2016, "innovation_type": "governance,policy", "cognitive_mechanism": "policy-design,typology", "key_researchers": ["Peter Kivimaa", "Florian Kern"], "key_works": ["Creative destruction or mere niche support? Innovation policy mixes for sustainability transitions (2016)"], "keywords_ja": "ガバナンス手段,政策ツール,ニッチ支援,レジーム不安定化,類型論", "keywords_en": "governance instruments, policy tools, niche support, regime destabilisation, typology", "opposing_concept_names": "single-instrument policy", "schumpeter_layer": "macro"},
    {"id": "inno_trans_244", "name_en": "Protective Space Reconceptualization", "name_ja": "保護空間の再概念化", "definition": "ニッチを取り巻く「保護空間」の概念を再検討し、シールディング（保護）・ナーチャリング（育成）・エンパワメント（権限付与）の3機能として精緻化した理論。保護空間の形成・維持・解除の条件を分析する。", "impact_summary": "ニッチ保護政策の理論的基盤を精緻化し、保護の程度と時期に関する政策的判断の枠組みを提供", "school_of_thought": "MLP学派", "era_start": 2012, "innovation_type": "systemic,policy", "cognitive_mechanism": "protection,nurturing", "key_researchers": ["Adrian Smith", "Rob Raven"], "key_works": ["What is protective space? Reconsidering niches in transitions to sustainability (2012)"], "keywords_ja": "保護空間,シールディング,ナーチャリング,エンパワメント,ニッチ", "keywords_en": "protective space, shielding, nurturing, empowerment, niche", "opposing_concept_names": "market exposure", "schumpeter_layer": "meso"},
    {"id": "inno_trans_245", "name_en": "MLP and Business Models for Sustainability", "name_ja": "MLPと持続可能性ビジネスモデル", "definition": "持続可能性志向のビジネスモデル革新をMLPフレームワークで分析する理論。ニッチにおける新しいビジネスモデルの出現とレジームレベルでのビジネスモデル変革の相互作用を扱う。", "impact_summary": "経営学のビジネスモデル論とトランジション研究を接続し、企業レベルのトランジション戦略の分析を可能に", "school_of_thought": "MLP学派", "era_start": 2014, "innovation_type": "systemic,business", "cognitive_mechanism": "business-model,value-creation", "key_researchers": ["Nancy Bocken", "Steve Evans", "Frank Geels"], "key_works": ["A literature and practice review to develop sustainable business model archetypes (2014)"], "keywords_ja": "MLP,ビジネスモデル,価値創造,持続可能性,サーキュラー", "keywords_en": "MLP, business models, value creation, sustainability, circular", "opposing_concept_names": "technology-only transition", "schumpeter_layer": "meso"},
    {"id": "inno_trans_246", "name_en": "Socio-Technical Imaginaries in Transitions", "name_ja": "トランジションにおける社会技術的想像力", "definition": "ジャサノフの「社会技術的想像力」概念をトランジション研究に導入し、持続可能な未来についての集合的ビジョンがトランジションの方向性と正当性に与える影響を分析する理論。", "impact_summary": "STS（科学技術社会論）とトランジション研究の対話を促進し、想像力の政治的機能を理論化", "school_of_thought": "MLP学派", "era_start": 2015, "innovation_type": "systemic,cultural", "cognitive_mechanism": "imaginary,collective-vision", "key_researchers": ["Sheila Jasanoff", "Sang-Hyun Kim"], "key_works": ["Dreamscapes of Modernity: Sociotechnical Imaginaries and the Fabrication of Power (2015)"], "keywords_ja": "社会技術的想像力,集合的ビジョン,未来像,正当性,STS", "keywords_en": "sociotechnical imaginaries, collective vision, future images, legitimacy, STS", "opposing_concept_names": "technocratic forecasting", "schumpeter_layer": "macro"},
    {"id": "inno_trans_247", "name_en": "Incumbent Firm Strategies in Transitions", "name_ja": "トランジションにおける既存企業戦略", "definition": "既存の大企業（インカンベント）がトランジションに対してとる多様な戦略—抵抗・適応・多角化・主導—を類型化する理論。既存企業がトランジションの推進者にも阻害者にもなりうることを分析する。", "impact_summary": "既存企業を一律に「抵抗勢力」と見なす見方を修正し、企業のトランジション戦略の多様性を理論化", "school_of_thought": "MLP学派", "era_start": 2014, "innovation_type": "systemic,strategic", "cognitive_mechanism": "strategy,adaptation", "key_researchers": ["Frank Geels", "Jochen Markard"], "key_works": ["Regime resistance against low-carbon transitions: Introducing politics and power into the multi-level perspective (2014)"], "keywords_ja": "既存企業,インカンベント,戦略,適応,抵抗,トランジション", "keywords_en": "incumbent firms, strategies, adaptation, resistance, transition", "opposing_concept_names": "new entrant-only transition", "schumpeter_layer": "meso"},
    {"id": "inno_trans_248", "name_en": "Polycentric Transition Governance", "name_ja": "多中心的トランジションガバナンス", "definition": "オストロムの多中心的ガバナンス理論をトランジション研究に応用し、複数の自律的なガバナンスセンターが相互作用しながらトランジションを形成するプロセスを分析するフレームワーク。", "impact_summary": "中央集権的トランジション管理の限界を指摘し、分散型ガバナンスの理論的正当化を提供", "school_of_thought": "トランジション論", "era_start": 2015, "innovation_type": "governance,distributed", "cognitive_mechanism": "polycentric,coordination", "key_researchers": ["Dave Huitema", "Andrew Jordan"], "key_works": ["The politics of climate change adaptation (2015)"], "keywords_ja": "多中心的ガバナンス,分散型,自律的,調整,オストロム", "keywords_en": "polycentric governance, distributed, autonomous, coordination, Ostrom", "opposing_concept_names": "centralized transition management", "schumpeter_layer": "macro"},
    {"id": "inno_trans_249", "name_en": "Narratives of Transition", "name_ja": "トランジションのナラティブ", "definition": "持続可能性トランジションをめぐる物語—進歩物語・危機物語・公正物語—がトランジションの政治的動員と方向性に与える影響を分析する理論。ナラティブの競合と覇権のダイナミクスを扱う。", "impact_summary": "トランジションの言説的次元を体系化し、コミュニケーション戦略の重要性を理論的に裏付け", "school_of_thought": "トランジション論", "era_start": 2014, "innovation_type": "systemic,cultural", "cognitive_mechanism": "narrative,framing", "key_researchers": ["Florian Kern", "Jochen Markard"], "key_works": ["Analysing energy transitions: Combining insights from transition studies and politics (2014)"], "keywords_ja": "ナラティブ,物語,フレーミング,言説,政治的動員", "keywords_en": "narratives, stories, framing, discourse, political mobilisation", "opposing_concept_names": "objective transition analysis", "schumpeter_layer": "macro"},
    {"id": "inno_trans_250", "name_en": "MLP and Quantitative Methods", "name_ja": "MLPと定量的手法", "definition": "定性的フレームワークであるMLPに定量的手法—計量書誌学・エージェントベースモデル・パテント分析—を統合する方法論的拡張。トランジションの速度・規模・パターンの定量的測定を目指す。", "impact_summary": "MLPの方法論的多元化を促進し、実証的裏付けの強化に貢献", "school_of_thought": "MLP学派", "era_start": 2016, "innovation_type": "systemic,methodological", "cognitive_mechanism": "quantitative,measurement", "key_researchers": ["Jochen Markard", "Marco Hekkert"], "key_works": ["Innovation studies and sustainability transitions: The allure of the multi-level perspective and its challenges (2012)"], "keywords_ja": "MLP,定量的手法,エージェントベースモデル,計量書誌学,パテント分析", "keywords_en": "MLP, quantitative methods, agent-based model, bibliometrics, patent analysis", "opposing_concept_names": "qualitative-only MLP", "schumpeter_layer": "macro"},
    {"id": "inno_trans_251", "name_en": "MLP and Health Systems", "name_ja": "MLPと医療システム", "definition": "MLPフレームワークを医療・公衆衛生システムのトランジション分析に応用する拡張。医療技術革新・制度変革・患者行動変化の相互作用によるヘルスケアシステム変革を分析する。", "impact_summary": "エネルギー・交通中心のトランジション研究を医療セクターに拡張し、ヘルスケア変革の構造的理解を促進", "school_of_thought": "MLP学派", "era_start": 2015, "innovation_type": "systemic,health", "cognitive_mechanism": "sectoral-application,health", "key_researchers": ["Anna Bergek", "Christian Berggren"], "key_works": ["Sociotechnical transitions in healthcare (2015)"], "keywords_ja": "MLP,医療システム,ヘルスケア,トランジション,制度変革", "keywords_en": "MLP, health systems, healthcare, transition, institutional change", "opposing_concept_names": "health policy incrementalism", "schumpeter_layer": "meso"},
    {"id": "inno_trans_252", "name_en": "MLP and Food System Transitions", "name_ja": "MLPと食料システムトランジション", "definition": "MLPフレームワークを食料システム（農業・加工・流通・消費）のトランジション分析に応用する理論。有機農業・アグロエコロジー等のニッチと産業的農業レジームの相互作用を分析する。", "impact_summary": "食料システムの持続可能性課題をトランジション理論で体系的に分析する枠組みを確立", "school_of_thought": "MLP学派", "era_start": 2010, "innovation_type": "systemic,sustainability,food", "cognitive_mechanism": "food-system,agro-ecology", "key_researchers": ["Harriet Friedmann", "Philip McMichael", "Adrian Smith"], "key_works": ["Sustainability transitions in food systems (2010)"], "keywords_ja": "MLP,食料システム,農業トランジション,アグロエコロジー,有機農業", "keywords_en": "MLP, food systems, agricultural transition, agroecology, organic farming", "opposing_concept_names": "industrial agriculture optimization", "schumpeter_layer": "macro"},
    {"id": "inno_trans_253", "name_en": "MLP and Water System Transitions", "name_ja": "MLPと水システムトランジション", "definition": "MLPを水管理・上下水道システムの長期的変革に適用する理論。中央集権的な水インフラから分散型・統合型水管理への移行プロセスを分析する。", "impact_summary": "水セクターの制度的ロックインと変革の構造的理解を提供し、統合水資源管理政策に示唆を付与", "school_of_thought": "MLP学派", "era_start": 2010, "innovation_type": "systemic,sustainability,water", "cognitive_mechanism": "infrastructure,water", "key_researchers": ["Jouni Paavola", "Jeroen van der Sluijs"], "key_works": ["Transitions in water management (2010)"], "keywords_ja": "MLP,水システム,水管理,インフラ,分散型", "keywords_en": "MLP, water systems, water management, infrastructure, decentralised", "opposing_concept_names": "centralized water management", "schumpeter_layer": "meso"},
    {"id": "inno_trans_254", "name_en": "Niche-Niche Interactions", "name_ja": "ニッチ間相互作用", "definition": "複数のニッチ革新間の協力・競合・共進化のダイナミクスを分析する理論。異なるニッチが相互に強化し合う条件と競合する条件を識別し、ニッチ・クラスターの形成メカニズムを解明する。", "impact_summary": "ニッチを孤立的に分析する従来の方法を超え、ニッチ間の相乗効果の重要性を理論化", "school_of_thought": "MLP学派", "era_start": 2016, "innovation_type": "systemic", "cognitive_mechanism": "interaction,synergy", "key_researchers": ["Jochen Markard", "Bernhard Truffer"], "key_works": ["Multi-regime dynamics in the analysis of sectoral transformation (2016)"], "keywords_ja": "ニッチ間相互作用,協力,競合,共進化,シナジー", "keywords_en": "niche-niche interactions, cooperation, competition, co-evolution, synergy", "opposing_concept_names": "isolated niche analysis", "schumpeter_layer": "meso"},
    {"id": "inno_trans_255", "name_en": "Acceleration Mechanisms in Transitions", "name_ja": "トランジションにおける加速メカニズム", "definition": "持続可能性トランジションの速度を加速する要因とメカニズム—政策加速・市場ティッピングポイント・社会運動・技術的ブレークスルー—を体系的に分析する理論。", "impact_summary": "トランジションの速度を上げるための介入ポイントを特定し、気候危機に対応するための「加速」戦略を理論化", "school_of_thought": "トランジション論", "era_start": 2020, "innovation_type": "systemic,sustainability", "cognitive_mechanism": "acceleration,tipping", "key_researchers": ["Benjamin Sovacool", "Frank Geels"], "key_works": ["How long will the energy transition take? (2016)"], "keywords_ja": "加速,ティッピングポイント,速度,トランジション速度", "keywords_en": "acceleration, tipping points, speed, transition speed", "opposing_concept_names": "gradual transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_256", "name_en": "MLP and Sustainability Assessment", "name_ja": "MLPと持続可能性評価", "definition": "MLPフレームワークを用いてトランジションの持続可能性パフォーマンスを評価する方法論。技術的効率性だけでなく、社会的・環境的・制度的側面を含む多次元的評価枠組みを提案する。", "impact_summary": "技術主導のトランジション評価を多次元的評価に拡張し、持続可能性の包括的測定を可能にした", "school_of_thought": "MLP学派", "era_start": 2015, "innovation_type": "systemic,assessment", "cognitive_mechanism": "evaluation,multi-criteria", "key_researchers": ["Andy Stirling", "Jan Rotmans"], "key_works": ["Transformative innovation for sustainability (2015)"], "keywords_ja": "MLP,持続可能性評価,多次元,パフォーマンス,指標", "keywords_en": "MLP, sustainability assessment, multi-dimensional, performance, indicators", "opposing_concept_names": "techno-economic assessment only", "schumpeter_layer": "macro"},
    {"id": "inno_trans_257", "name_en": "Niche Governance Strategies", "name_ja": "ニッチガバナンス戦略", "definition": "ニッチ革新の発展を支援するためのガバナンス戦略を体系化した理論。資金提供・規制緩和・学習支援・ネットワーキング・ビジョン形成の5つの戦略的機能を識別する。", "impact_summary": "ニッチ支援政策の設計に体系的なフレームワークを提供", "school_of_thought": "MLP学派", "era_start": 2013, "innovation_type": "governance,strategic", "cognitive_mechanism": "strategy,support", "key_researchers": ["Derk Loorbach", "Jan Rotmans"], "key_works": ["Governance of transitions: Niches, regimes and systems (2013)"], "keywords_ja": "ニッチガバナンス,戦略,支援,資金提供,規制緩和", "keywords_en": "niche governance, strategies, support, funding, deregulation", "opposing_concept_names": "laissez-faire niche development", "schumpeter_layer": "meso"},
    {"id": "inno_trans_258", "name_en": "MLP and Distributional Effects", "name_ja": "MLPと分配的効果", "definition": "トランジションプロセスの費用と便益が社会集団間でどのように不均等に分配されるかを分析するフレームワーク。トランジションの勝者と敗者の問題を理論化する。", "impact_summary": "トランジションの社会的公正性を正面から分析する枠組みを確立し、公正なトランジション政策への理論的貢献", "school_of_thought": "トランジション論", "era_start": 2018, "innovation_type": "systemic,social", "cognitive_mechanism": "distributional,justice", "key_researchers": ["Raphael Heffron", "Darren McCauley"], "key_works": ["The concept of energy justice across the disciplines (2017)"], "keywords_ja": "MLP,分配的効果,公正性,勝者と敗者,社会的影響", "keywords_en": "MLP, distributional effects, justice, winners and losers, social impacts", "opposing_concept_names": "efficiency-only transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_259", "name_en": "Regime Reconfiguration from Within", "name_ja": "レジーム内部からの再構成", "definition": "レジーム行為者（既存大企業・政策機関）が内部改革を通じてレジームを段階的に変革するプロセスの理論。完全な体制転覆ではなく、既存構造の修正的変革の可能性を分析する。", "impact_summary": "ラディカルなシステム変革だけでなく、改良主義的変革経路の正当性を理論化", "school_of_thought": "MLP学派", "era_start": 2016, "innovation_type": "systemic,institutional", "cognitive_mechanism": "reform,incremental", "key_researchers": ["Frank Geels"], "key_works": ["Socio-technical transitions for deep decarbonization (2017)"], "keywords_ja": "レジーム再構成,内部改革,段階的変革,既存構造", "keywords_en": "regime reconfiguration, internal reform, incremental change, existing structures", "opposing_concept_names": "revolutionary transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_260", "name_en": "MLP and Actor-Network Theory Integration", "name_ja": "MLPとアクターネットワーク理論の統合", "definition": "ラトゥールのアクターネットワーク理論（ANT）とMLPの統合を試みる理論的枠組み。人間と非人間のアクターのネットワーク形成がトランジションに与える影響を分析する。", "impact_summary": "STS（科学技術社会論）の中核理論とトランジション研究の対話を促進し、方法論的革新を刺激", "school_of_thought": "MLP学派", "era_start": 2010, "innovation_type": "systemic,theoretical", "cognitive_mechanism": "network,relational", "key_researchers": ["Frank Geels", "Rob Raven"], "key_works": ["MLP and ANT in transitions research (2010)"], "keywords_ja": "MLP,ANT,アクターネットワーク,ラトゥール,非人間アクター", "keywords_en": "MLP, ANT, actor-network theory, Latour, non-human actors", "opposing_concept_names": "human-centric MLP", "schumpeter_layer": "macro"},
    {"id": "inno_trans_261", "name_en": "Transition Monitoring and Evaluation Framework", "name_ja": "トランジションのモニタリング・評価フレームワーク", "definition": "持続可能性トランジションの進行状況を体系的にモニタリングし評価するためのフレームワーク。ニッチ成長指標・レジーム変化指標・ランドスケープ圧力指標の3層を統合する。", "impact_summary": "トランジション政策の効果測定と適応的修正のための実践的ツールを提供", "school_of_thought": "トランジション論", "era_start": 2014, "innovation_type": "governance,assessment", "cognitive_mechanism": "monitoring,evaluation", "key_researchers": ["René Kemp", "Derk Loorbach"], "key_works": ["Transition monitoring and evaluation framework (2014)"], "keywords_ja": "モニタリング,評価,指標,進捗測定,適応的管理", "keywords_en": "monitoring, evaluation, indicators, progress measurement, adaptive management", "opposing_concept_names": "static policy evaluation", "schumpeter_layer": "macro"},
    {"id": "inno_trans_262", "name_en": "MLP and Circular Economy Nexus", "name_ja": "MLPとサーキュラーエコノミーの接合", "definition": "MLPフレームワークをサーキュラーエコノミーへのトランジション分析に適用する理論。線形経済レジームからサーキュラーエコノミーへの移行をニッチ・レジーム・ランドスケープの相互作用で分析する。", "impact_summary": "サーキュラーエコノミー研究にシステムトランジションの視点を導入し、循環型社会への移行のガバナンスを理論化", "school_of_thought": "MLP学派", "era_start": 2018, "innovation_type": "systemic,sustainability,circular", "cognitive_mechanism": "circular,systemic", "key_researchers": ["Jouni Korhonen", "Nancy Bocken"], "key_works": ["Circular economy transitions: A systematic review (2018)"], "keywords_ja": "MLP,サーキュラーエコノミー,循環型経済,線形経済,トランジション", "keywords_en": "MLP, circular economy, linear economy, transition, resource loops", "opposing_concept_names": "linear economy optimization", "schumpeter_layer": "macro"},
    {"id": "inno_trans_263", "name_en": "Sustainability Transition Failures", "name_ja": "持続可能性トランジションの失敗", "definition": "持続可能性トランジションが失敗する条件・パターン・メカニズムを分析する理論。政策失敗・技術的失敗・社会的拒絶・制度的抵抗の複合的原因を体系化する。", "impact_summary": "成功バイアスを是正し、トランジションの失敗からの学習メカニズムを理論化", "school_of_thought": "トランジション論", "era_start": 2017, "innovation_type": "systemic", "cognitive_mechanism": "failure,learning", "key_researchers": ["Bruno Turnheim", "Frank Geels"], "key_works": ["Evaluating sustainability transitions pathways: Bridging analytical approaches (2015)"], "keywords_ja": "トランジション失敗,失敗分析,学習,政策失敗", "keywords_en": "transition failures, failure analysis, learning, policy failure", "opposing_concept_names": "transition success narrative", "schumpeter_layer": "macro"},
    {"id": "inno_trans_264", "name_en": "MLP and Indigenous Knowledge Systems", "name_ja": "MLPと先住民知識システム", "definition": "MLPフレームワークに先住民の知識・実践・世界観を統合する拡張。西洋近代的な社会技術概念を脱植民地化し、先住民の持続可能性実践をニッチ革新として位置づける。", "impact_summary": "トランジション研究の認識論的多元化を促進し、先住民知識のトランジションへの貢献を可視化", "school_of_thought": "MLP学派", "era_start": 2020, "innovation_type": "systemic,inclusive,cultural", "cognitive_mechanism": "decolonial,indigenous", "key_researchers": ["Bipashyee Ghosh", "Rob Raven"], "key_works": ["Decolonising transitions research (2020)"], "keywords_ja": "MLP,先住民知識,脱植民地化,多元的知識,包摂性", "keywords_en": "MLP, indigenous knowledge, decolonisation, pluralist knowledge, inclusivity", "opposing_concept_names": "Western-centric MLP", "schumpeter_layer": "macro"},
    {"id": "inno_trans_265", "name_en": "Transition Conflicts and Contestation", "name_ja": "トランジションにおける紛争と異議", "definition": "持続可能性トランジションに伴う社会的紛争—土地利用紛争・エネルギー立地紛争・分配的紛争—のダイナミクスと解決メカニズムを分析する理論。紛争がトランジションを阻害するだけでなく促進する可能性も分析する。", "impact_summary": "トランジションの紛争的次元を体系的に分析し、紛争管理のガバナンス枠組みを提供", "school_of_thought": "トランジション論", "era_start": 2016, "innovation_type": "systemic,social,political", "cognitive_mechanism": "conflict,contestation", "key_researchers": ["Flor Avelino", "Julia Wittmayer"], "key_works": ["Shifting power relations in sustainability transitions (2016)"], "keywords_ja": "紛争,異議申立て,反対運動,NIMBY,分配的公正", "keywords_en": "conflicts, contestation, opposition, NIMBY, distributional justice", "opposing_concept_names": "consensus-based transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_266", "name_en": "Post-Normal Science and Transitions", "name_ja": "ポストノーマルサイエンスとトランジション", "definition": "ファントヴィッチとラヴェッツのポストノーマルサイエンス概念をトランジション研究に適用する理論。高い不確実性・高い利害関心の下でのトランジション知識の生産と意思決定を分析する。", "impact_summary": "トランジション研究の認識論的前提を問い直し、不確実性下での知識生産の方法論的課題を理論化", "school_of_thought": "トランジション論", "era_start": 2013, "innovation_type": "systemic,epistemological", "cognitive_mechanism": "uncertainty,post-normal", "key_researchers": ["Silvio Funtowicz", "Jerome Ravetz"], "key_works": ["Science for the post-normal age (1993)"], "keywords_ja": "ポストノーマルサイエンス,不確実性,利害関心,拡張的ピアレビュー", "keywords_en": "post-normal science, uncertainty, stakes, extended peer review", "opposing_concept_names": "normal science approach", "schumpeter_layer": "macro"},
    {"id": "inno_trans_267", "name_en": "MLP and Migration-Sustainability Nexus", "name_ja": "MLPと移民-持続可能性ネクサス", "definition": "人口移動・移民・都市化がトランジションのダイナミクスに与える影響を分析するフレームワーク。グローバルな人口移動がニッチ革新の伝播やレジーム変化に果たす役割を理論化する。", "impact_summary": "人口動態の変化をトランジション分析に統合し、移民がもたらす革新的実践の伝播メカニズムを解明", "school_of_thought": "MLP学派", "era_start": 2019, "innovation_type": "systemic,social", "cognitive_mechanism": "migration,diffusion", "key_researchers": ["Bipashyee Ghosh"], "key_works": ["Migration and sustainability transitions (2019)"], "keywords_ja": "MLP,移民,人口移動,都市化,知識伝播", "keywords_en": "MLP, migration, population movement, urbanization, knowledge diffusion", "opposing_concept_names": "static population MLP", "schumpeter_layer": "macro"},
    {"id": "inno_trans_268", "name_en": "MLP and Gender Dimensions", "name_ja": "MLPとジェンダー次元", "definition": "MLPフレームワークにジェンダー分析を統合し、トランジションプロセスにおけるジェンダー不平等の再生産と変革の可能性を分析する理論。技術選択・政策設計・参加構造のジェンダー的含意を扱う。", "impact_summary": "トランジション研究のジェンダーブラインドネスを是正し、包摂的なトランジション政策の設計に貢献", "school_of_thought": "トランジション論", "era_start": 2019, "innovation_type": "systemic,social,gender", "cognitive_mechanism": "gender,inclusivity", "key_researchers": ["Joy Clancy", "Mariëlle Feenstra"], "key_works": ["Gender and energy: A framework for analysis (2019)"], "keywords_ja": "MLP,ジェンダー,不平等,包摂性,フェミニスト分析", "keywords_en": "MLP, gender, inequality, inclusivity, feminist analysis", "opposing_concept_names": "gender-blind transition", "schumpeter_layer": "macro"},
    {"id": "inno_trans_269", "name_en": "MLP and Behavioral Economics", "name_ja": "MLPと行動経済学", "definition": "行動経済学の知見—限定合理性・ナッジ・フレーミング効果・現在バイアス—をMLPフレームワークに統合する理論。ユーザーの意思決定の非合理性がトランジションの速度と方向に与える影響を分析する。", "impact_summary": "合理的行為者仮定を超えたトランジション分析を可能にし、行動的政策介入の理論的基盤を提供", "school_of_thought": "MLP学派", "era_start": 2017, "innovation_type": "systemic,behavioral", "cognitive_mechanism": "behavioral,nudge", "key_researchers": ["Charlie Wilson", "Frank Geels"], "key_works": ["Behavioral models of energy use (2017)"], "keywords_ja": "MLP,行動経済学,ナッジ,限定合理性,現在バイアス", "keywords_en": "MLP, behavioral economics, nudge, bounded rationality, present bias", "opposing_concept_names": "rational actor MLP", "schumpeter_layer": "micro"},
    {"id": "inno_trans_270", "name_en": "MLP and Complex Systems Theory", "name_ja": "MLPと複雑系理論", "definition": "複雑適応系理論の概念—創発・自己組織化・非線形性・ティッピングポイント—をMLPに統合する理論的枠組み。トランジションのダイナミクスを複雑系の振る舞いとして再解釈する。", "impact_summary": "MLPの理論的基盤を複雑系科学で強化し、トランジションの予測不可能性と非線形性の理解を深化", "school_of_thought": "MLP学派", "era_start": 2013, "innovation_type": "systemic,theoretical", "cognitive_mechanism": "complexity,emergence", "key_researchers": ["Jan Rotmans", "Derk Loorbach"], "key_works": ["Complexity and Transition Management (2009)"], "keywords_ja": "MLP,複雑系,創発,自己組織化,非線形,ティッピングポイント", "keywords_en": "MLP, complex systems, emergence, self-organisation, non-linearity, tipping points", "opposing_concept_names": "linear transition model", "schumpeter_layer": "macro"},
    {"id": "inno_trans_271", "name_en": "Niche Internal Governance", "name_ja": "ニッチの内部ガバナンス", "definition": "ニッチ革新の内部における組織的・制度的ガバナンスの構造とプロセスを分析する理論。ニッチ内部の権力関係・意思決定メカニズム・学習プロセスがニッチの成功に与える影響を扱う。", "impact_summary": "ニッチの外部環境だけでなく内部ダイナミクスの分析を体系化", "school_of_thought": "MLP学派", "era_start": 2014, "innovation_type": "governance,organizational", "cognitive_mechanism": "governance,internal", "key_researchers": ["Derk Loorbach", "Julia Wittmayer"], "key_works": ["Governance in sustainability transitions (2014)"], "keywords_ja": "ニッチ内部,ガバナンス,権力,意思決定,学習", "keywords_en": "niche internal, governance, power, decision-making, learning", "opposing_concept_names": "niche-environment focus", "schumpeter_layer": "micro"},
    {"id": "inno_trans_272", "name_en": "MLP and COVID-19 Disruptions", "name_ja": "MLPとCOVID-19の破壊的影響", "definition": "COVID-19パンデミックをMLPのランドスケープショックとして分析し、パンデミックがトランジションに与えた加速・減速・方向転換の効果を評価する理論。危機がシステム変革の「機会の窓」を開く条件を分析する。", "impact_summary": "パンデミックを通じたMLPの実証的検証と精緻化に貢献し、危機駆動型トランジションの理解を深化", "school_of_thought": "MLP学派", "era_start": 2020, "innovation_type": "systemic,crisis", "cognitive_mechanism": "crisis,disruption", "key_researchers": ["Frank Geels", "Benjamin Sovacool"], "key_works": ["The socio-technical dynamics of COVID-19 and sustainability transitions (2020)"], "keywords_ja": "MLP,COVID-19,パンデミック,ランドスケープショック,危機", "keywords_en": "MLP, COVID-19, pandemic, landscape shock, crisis", "opposing_concept_names": "pre-pandemic transition theory", "schumpeter_layer": "macro"},
    {"id": "inno_trans_273", "name_en": "MLP and Demand-Side Transitions", "name_ja": "MLPと需要側トランジション", "definition": "エネルギー・モビリティ・食料の消費・需要側のトランジションをMLPで分析する理論。社会実践の変化・消費者行動・ライフスタイルトランジションのシステム的側面を扱う。", "impact_summary": "供給側中心のトランジション分析を補完し、需要側の変革が持つトランジション促進機能を理論化", "school_of_thought": "MLP学派", "era_start": 2018, "innovation_type": "systemic,demand-side", "cognitive_mechanism": "consumption,practice", "key_researchers": ["Charlie Wilson", "Elizabeth Shove"], "key_works": ["Demand-side solutions for climate change mitigation (2018)"], "keywords_ja": "MLP,需要側,消費,ライフスタイル,実践変化", "keywords_en": "MLP, demand-side, consumption, lifestyle, practice change", "opposing_concept_names": "supply-side transition", "schumpeter_layer": "micro"},
    {"id": "inno_trans_274", "name_en": "MLP and Policy Feedback Loops", "name_ja": "MLPと政策フィードバックループ", "definition": "政策がトランジションダイナミクスに影響を与え、そのトランジションが新たな政策条件を生み出す循環的プロセスを分析する理論。正のフィードバック（加速）と負のフィードバック（減速）の両方を扱う。", "impact_summary": "政策とトランジションの相互構成的関係を理論化し、適応的政策設計の重要性を裏付け", "school_of_thought": "トランジション論", "era_start": 2017, "innovation_type": "governance,systemic", "cognitive_mechanism": "feedback,adaptive", "key_researchers": ["Florian Kern", "Peter Kivimaa"], "key_works": ["Policy feedback in sustainability transitions (2017)"], "keywords_ja": "政策フィードバック,循環的,正のフィードバック,負のフィードバック,適応的", "keywords_en": "policy feedback, circular, positive feedback, negative feedback, adaptive", "opposing_concept_names": "linear policy model", "schumpeter_layer": "macro"},
    {"id": "inno_trans_275", "name_en": "MLP and Path Creation", "name_ja": "MLPと経路創造", "definition": "経路依存性の対概念としての「経路創造」をMLPフレームワークに統合する理論。行為者がいかにして既存のロックインを克服し、新たなトランジション経路を意図的に構築するかを分析する。", "impact_summary": "決定論的な経路依存性論を超え、トランジションにおける行為者のエージェンシーの可能性を理論化", "school_of_thought": "MLP学派", "era_start": 2010, "innovation_type": "systemic,strategic", "cognitive_mechanism": "path-creation,agency", "key_researchers": ["Raghu Garud", "Peter Karnøe"], "key_works": ["Path creation as a process of mindful deviation (2001)"], "keywords_ja": "経路創造,ロックイン克服,行為主体性,意図的変革", "keywords_en": "path creation, lock-in overcoming, agency, intentional transformation", "opposing_concept_names": "path dependence determinism", "schumpeter_layer": "meso"},
    {"id": "inno_trans_276", "name_en": "MLP and Inter-generational Perspectives", "name_ja": "MLPと世代間視点", "definition": "トランジションプロセスにおける世代間ダイナミクス—若者の活動主義・世代交代・世代間公正—の役割を分析する理論。気候運動における若年世代の役割とレジーム変革への影響を扱う。", "impact_summary": "世代間の視点をトランジション分析に統合し、世代間公正の問題をシステム変革の文脈で理論化", "school_of_thought": "トランジション論", "era_start": 2019, "innovation_type": "systemic,social", "cognitive_mechanism": "generational,justice", "key_researchers": ["Julia Wittmayer", "Flor Avelino"], "key_works": ["Intergenerational perspectives on sustainability transitions (2019)"], "keywords_ja": "世代間,若者,活動主義,世代間公正,気候運動", "keywords_en": "intergenerational, youth, activism, intergenerational justice, climate movement", "opposing_concept_names": "generation-blind transition", "schumpeter_layer": "macro"},
